    [StoreId.GoodsStore] = { title_name = "gui_bed_war_shop_title" },
    [StoreId.UpgradeStore] = { title_name = "gui_bed_war_lvshop_title" },
    [StoreId.CubeStore] = { title_name = "gui_str_app_shop_shop" },
}

local UIStore = class("GUIStore", IGUILayout)

function UIStore:onLoad()
    self.curShowType = 0
    self.curSelectGoods = nil
    self.curTipKey = nil

    local llMain = self:getChildWindow("BedWarStore-Main", GUIType.Layout)
    local size = llMain:GetPixelSize()
    local width = math.min((size.y / 574) * 1138, size.x)
    llMain:SetWidth({ 0, width })

