    self.lvTabs:setArea({ 0, 8 }, { 0, 8 }, { 1, -16 }, { 1, -16 })
    self.lvTabs:setItemSpace(8)

    self.llMoney = self:getChildWindow("BedWarStore-Money", GUIType.Layout)
    self.lvMoney = IGUIListView.new("BedWarStore-Money-List", self.llMoney, nil, Orientation.Horizontal)
    self.lvMoney:setItemSpace(30)
    self.maxMoneyWidth = self.llMoney:GetPixelSize().x

    local llGoodsList = self:getChildWindow("BedWarStore-GoodsList", GUIType.Layout)
    self.gvGoodsList = IGUIGridView.new("BedWarStore-Goods-List-Gird", llGoodsList)
    self.gvGoodsList:setConfig(12, 8, 4)
    self.goodsAdapter = require("game.ui.adapter.StoreGoodsAdapter").new()
    local contentWidth = self.gvGoodsList:getWidth()
    local itemWidth = (contentWidth - 39) / 4
    local itemHeight = (itemWidth / 142) * 190
    self.goodsAdapter:setItemSize(itemWidth, itemHeight)
    self.gvGoodsList:setAdapter(self.goodsAdapter)

    self.tvTitleText = self:getChildWindow("BedWarStore-Title-Text", GUIType.StaticText)

    self.tvGoodsName = self:getChildWindow("BedWarStore-Goods-Name", GUIType.StaticText)
    self.ivGoodsImage = self:getChildWindow("BedWarStore-Goods-Image", GUIType.StaticImage)
    self.tvGoodsDesc = self:getChildWindow("BedWarStore-Goods-Desc", GUIType.StaticText)
    self.btnGoodsBuy = self:getChildWindow("BedWarStore-Goods-Buy", GUIType.Button)
    self.ivGoodsMoneyIcon = self:getChildWindow("BedWarStore-Goods-Money-Icon", GUIType.StaticImage)
    self.tvGoodsMoneyText = self:getChildWindow("BedWarStore-Goods-Money-Text", GUIType.StaticText)
    self.btnSkin = self:getChildWindow("BedWarStore-Skin", GUIType.Button)

    self.tvTips = self:getChildWindow("BedWarStore-Tips", GUIType.StaticText)
    self.tvTips:SetVisible(false)

    local btnClose = self:getChildWindow("BedWarStore-Close", GUIType.Button)
    btnClose:registerEvent(GUIEvent.ButtonClick, function()
        self:hide(true)
    end)

    local btnCloseMask = self:getChildWindow("BedWarStore-Close-Mask", GUIType.Button)
    btnCloseMask:registerEvent(GUIEvent.ButtonClick, function()
        self:hide(true)
