function UIStore:isShowAnim()
    return false
end

function UIStore:show(playSound, ...)
    if playSound then
        SoundUtil.playSound(SoundConfig.openStore)
    end
    self.super.show(self, playSound, ...)
end

function UIStore:hide(playSound)
    if playSound then
        SoundUtil.playSound(SoundConfig.closeStore)
    end
    self.super.hide(self)
end

function UIStore:onBuyGoodsSuccess(goods)
    local count = GoodsStorePrivilege:onBuyGoods(goods)
    if goods.TabId < 1000 or GameConfig.useNewLottery ~= 1 then
        if #goods.Image > 10 then
            HostApi.notifyGetGoods(goods.Image, count)
        else
            HostApi.notifyGetItem(goods.ItemId, 0, count)
        end
    end
    self:updateListUI()
    if goods.LevelGroup ~= "#" and not goods.SkipLevel then
        local _goods = StoreConfig:getNextUpgradeGoods(goods.ItemId)
        if _goods then
            self:showGoodsDetail(_goods)
        end
    else
        self.curSelectGoods = nil
        self:showGoodsDetail(goods)
    end
end

function UIStore:updateListUI()
    if not self:isShow() then
        return
    end
    ClientStore:checkAllUpgradeGoods()
    self.goodsAdapter:notifyDataChange()
end

function UIStore:trySelectTab(tabId)
    if not tabId then
        return
    end
    local items = self.lvTabs.items
    for _, item in pairs(items) do
        if item.tabId == tabId then
            item:setChecked(true)
        end
    end
end

function UIStore:onShow(type, tabId)
    self:updateListUI()
    local oldGoods = self.curSelectGoods
    self.curSelectGoods = nil
    self:showGoodsDetail(oldGoods)
    if self.curShowType == type then
        self:trySelectTab(tabId)
        return
    end
    self.curShowType = type

    local ui_config = StoreUIConfig[type]
    if ui_config then
        self.tvTitleText:SetText(Lang:getString(ui_config.title_name))
    end

    local config = StoreConfig:getStoreConfig(self.curShowType)
    self.lvTabs:clearItems()

    for index, data in pairs(config.Tabs) do
        local tab = GUIStoreTab.new("BedWarStoreTab.json")
        tab:onDataChanged(data)
        tab:setWidth({ 1, 0 })
        self.lvTabs:addItem(tab)
        if index == 1 then
            tab:setChecked(true)
        end
    end
    self.lvMoney:clearItems()
    local width = math.min(#config.CurrencyList * 200, self.maxMoneyWidth)
    self.llMoney:SetWidth({ 0, width })
    for _, data in pairs(config.CurrencyList) do
        local money = GUICurrency.new("BedWarCurrency.json")
        money:onDataChanged(data)
        self.lvMoney:addItem(money)
    end
    self:trySelectTab(tabId)
end

function UIStore:onTick()
    for _, item in pairs(self.lvMoney.items) do
        item:onTick()
    end
end

function UIStore:onSelectTab(tab)
    local items = self.lvTabs.items
    for _, item in pairs(items) do
        if item ~= tab then
            item:setChecked(false)
        end
    end
    self:showGoodsList(tab.tabId)
    if self.curShowType == StoreId.GoodsStore then
        GameAnalytics:design(1, { "page_goodsshop", tostring(tab.tabId) })
    elseif self.curShowType == StoreId.CubeStore then
        if GameType == "g1046" then
            GameAnalytics:design(1, { "H_cube_shop_page", tostring(tab.tabId) })
        else
            GameAnalytics:design(1, { "G_cube_shop_page", tostring(tab.tabId) })
        end

    end
end

function UIStore:showGoodsList(tabId)
    local config = StoreConfig:getStoreConfig(self.curShowType)
    local goods = {}
    for _, tab in pairs(config.Tabs) do
        if tab.Id == tabId then
            goods = tab.GoodsList
        end
    end
    if #goods > 0 then
        self:showGoodsDetail(goods[1])
    end
    self.goodsAdapter:setData(goods)
end

function UIStore:showGoodsDetail(goods)
    if self.curSelectGoods == goods then
        return
    end
    local oldGoods = self.curSelectGoods
    self.curSelectGoods = nil
    self.goodsAdapter:notifyItemDataChange(oldGoods)
    self.curSelectGoods = goods
    ClientStore:setGoodsUI(self.tvGoodsName, self.ivGoodsImage, self.ivGoodsMoneyIcon, self.tvGoodsMoneyText, self.btnGoodsBuy, goods)
    self.btnSkin:SetVisible(goods.BlockShopTabId ~= nil)
    self.tvGoodsDesc:SetText(Lang:getString(goods.Desc))
    self.goodsAdapter:notifyItemDataChange(goods)
    local storeId = StoreConfig:getGoodsStoreId(self.curSelectGoods)
    if storeId == StoreId.GoodsStore then
        GameAnalytics:design(1, { "select_goodsshop", tostring(goods.Id) })
    elseif storeId == StoreId.CubeStore then
        GameAnalytics:design(1, { "select_culbshop", tostring(goods.Id) })
    end
end

function UIStore:getCurrentGoodsId()
    if self.curSelectGoods then
        return self.curSelectGoods.Id
    end
    return 0
end

function UIStore:showTips(tips)
    self.tvTips:SetText(tips)
    self.tvTips:SetVisible(true)
    LuaTimer:cancel(self.curTipKey)
    self.curTipKey = LuaTimer:schedule(function()
        self.tvTips:SetVisible(false)
    end, 1000)
end

function UIStore:onBuyGoods(goods)
    ClientStore:onBuyGoods(goods, function(success, tips)
        if tips and #tips > 0 then
            self:showTips(tips)
        end
        if success then
            self:showGoodsDetail(goods)
        end
    end)
end

return UIStore